blocks.body:
{
    "level": "B2–C1",
    "intro": "W tym temacie dowiesz się szczegółowo <strong>czasownika biernego</strong>: jak tworzyć proste (w trakcie) i doskonałe (będące zrobione) bierne gerundy, kiedy ich używać i po jakich słowach.",
    "rules": [
        {
            "label": "Prosty",
            "color": "emerald",
            "text": "<strong>bycie + V3 (Imiesłów bierny)</strong> — działanie jednoczesne:",
            "example": "She hates being interrupted."
        },
        {
            "label": "Doskonały",
            "color": "blue",
            "text": "<strong>byłem + V3</strong> — poprzednia akcja:",
            "example": "Having been warned, he was careful."
        },
        {
            "label": "Porównanie",
            "color": "rose",
            "text": "Aktywny: <strong>robię / zrobiłem</strong> → Pasywny: <strong>robię / zrobiłem</strong>",
            "example": "writing → being written → having been written"
        }
    ]
}

{
    "title": "1. Tworzenie biernego gerunda",
    "intro": "Porównanie aktywnych i pasywnych form gerunda:",
    "items": [
        {
            "label": "Aktywny prosty",
            "title": "robić/pisać",
            "subtitle": "Lubię pisać listy. - Lubię pisać listy."
        },
        {
            "label": "Pasywny prosty",
            "title": "jest zrobione / jest pisane",
            "subtitle": "Nie lubi być krytykowany. - Nie lubi być krytykowany."
        },
        {
            "label": "Aktywny Idealny",
            "title": "zrobiłem / napisałem",
            "subtitle": "Skończywszy pracę, wyszła. — Po skończeniu pracy wyszła."
        },
        {
            "label": "Pasywny Idealny",
            "title": "zostało zrobione / zostało napisane",
            "subtitle": "Ponieważ została odrzucona, próbowała ponownie. — Otrzymawszy odmowę, próbowała ponownie."
        }
    ]
}

{
    "title": "2. Prosty bierny gerund (w trakcie)",
    "sections": [
        {
            "label": "Po czasownikach wyrażających uczucia",
            "color": "emerald",
            "description": "Після <strong>lubić, nienawidzić, cieszyć się, kochać, nie lubić, unikać, myśleć</strong>:",
            "examples": [
                {
                    "en": "She hates being interrupted.",
                    "ua": "Nienawidzi, gdy jej przeszkadzano."
                },
                {
                    "en": "Nobody likes being criticized.",
                    "ua": "Nikt nie lubi być krytykowany."
                },
                {
                    "en": "He enjoys being praised.",
                    "ua": "Lubi być chwalony."
                },
                {
                    "en": "I don't mind being asked questions.",
                    "ua": "Nie przeszkadza mi zadawanie pytań."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "blue",
            "description": "Після <strong>bez, po, przed, pomimo, zamiast, na</strong>:",
            "examples": [
                {
                    "en": "He left without being noticed.",
                    "ua": "Pozostawił niezauważony."
                },
                {
                    "en": "After being rejected, she applied again.",
                    "ua": "Po odrzuceniu złożyła ponownie wniosek."
                },
                {
                    "en": "Despite being warned, he continued.",
                    "ua": "Pomimo ostrzeżenia kontynuował."
                },
                {
                    "en": "Before being hired, she had to pass a test.",
                    "ua": "Zanim została zatrudniona, musiała przejść test."
                }
            ]
        },
        {
            "label": "Po zapamiętaniu/zapomnieniu/zaprzeczeniu",
            "color": "amber",
            "description": "Kiedy podmiot jest <strong>przedmiotem działania</strong>:",
            "examples": [
                {
                    "en": "I remember being told about it.",
                    "ua": "Pamiętam, że mi o tym powiedziano."
                },
                {
                    "en": "She denies being involved.",
                    "ua": "Zaprzecza swemu zaangażowaniu."
                },
                {
                    "en": "He will never forget being helped by her.",
                    "ua": "Nigdy nie zapomni, jak mu pomogła."
                }
            ]
        }
    ]
}

{
    "title": "3. Doskonały bierny gerund (zrobiony)",
    "sections": [
        {
            "label": "Przyczyna → skutek",
            "color": "emerald",
            "description": "W przypadku działań, które <strong>wyprzedziły inne</strong> i stały się ich przyczyną:",
            "examples": [
                {
                    "en": "Having been warned, he was more careful.",
                    "ua": "Otrzymawszy ostrzeżenie, był bardziej ostrożny."
                },
                {
                    "en": "Having been told the truth, she felt relieved.",
                    "ua": "Gdy poznała prawdę, poczuła ulgę."
                },
                {
                    "en": "Having been rejected twice, he gave up.",
                    "ua": "Po dwukrotnym odrzuceniu poddał się."
                }
            ]
        },
        {
            "label": "Styl formalny",
            "color": "blue",
            "description": "Często w <strong>naukowym i oficjalnym</strong> piśmie:",
            "examples": [
                {
                    "en": "Having been approved by the board, the project will begin.",
                    "ua": "Po zatwierdzeniu przez Radę inwestycja ruszy."
                },
                {
                    "en": "Having been elected, she took office immediately.",
                    "ua": "Po wyborze natychmiast objęła urząd."
                },
                {
                    "en": "Having been tested, the product was released.",
                    "ua": "Po testach produkt został wydany."
                }
            ]
        },
        {
            "label": "Po przyimkach",
            "color": "rose",
            "description": "Aby podkreślić <strong>poprzednią czynność</strong>:",
            "examples": [
                {
                    "en": "After having been informed, he took action.",
                    "ua": "Po otrzymaniu informacji podjął działania."
                },
                {
                    "en": "Despite having been warned, she ignored the advice.",
                    "ua": "Pomimo ostrzeżenia zignorowała tę radę."
                },
                {
                    "en": "On having been asked, he explained everything.",
                    "ua": "Zapytany, wszystko wyjaśnił."
                }
            ]
        }
    ]
}

{
    "title": "4. Słowa i wyrażenia z bierną gerundą",
    "sections": [
        {
            "label": "Czasowniki wyrażające uczucia",
            "color": "emerald",
            "description": "<strong>lubię, kocham, nienawidzę, cieszę się, nie lubię, wolę, unikam, przeszkadzam, nie mogę znieść</strong>:",
            "examples": [
                {
                    "en": "I can't stand being ignored.",
                    "ua": "Nienawidzę być ignorowana."
                },
                {
                    "en": "She avoids being seen by him.",
                    "ua": "Unika, żeby ją zobaczył."
                },
                {
                    "en": "They prefer being given clear instructions.",
                    "ua": "Wolą jasne instrukcje."
                }
            ]
        },
        {
            "label": "Czasowniki pamięci / mowy",
            "color": "blue",
            "description": "<strong>pamiętaj, zapomnij, zaprzeczaj, przyznaj się, przypomnij, wspomnij</strong>:",
            "examples": [
                {
                    "en": "He admitted being wrong.",
                    "ua": "Przyznał, że się mylił."
                },
                {
                    "en": "She recalls being praised by her teacher.",
                    "ua": "Pamięta, jak chwaliła ją nauczycielka."
                },
                {
                    "en": "He mentioned being offered a job.",
                    "ua": "Przypomniał sobie, że zaproponowano mu pracę."
                }
            ]
        },
        {
            "label": "Stabilne wyrażenia",
            "color": "amber",
            "description": "<strong>być wartym, przyzwyczajonym, niecierpliwym, bać się</strong>:",
            "examples": [
                {
                    "en": "The book is worth being read.",
                    "ua": "Tę książkę warto przeczytać."
                },
                {
                    "en": "She is used to being watched.",
                    "ua": "Jest przyzwyczajona do bycia obserwowaną."
                },
                {
                    "en": "I'm afraid of being punished.",
                    "ua": "Boję się, że zostanę ukarany."
                }
            ]
        }
    ]
}

{
    "title": "5. Porównanie: zrobione i zrobione",
    "intro": "Kiedy używać prostego lub doskonałego biernego gerunda:",
    "rows": [
        {
            "en": "being done",
            "ua": "Jednoczesne działanie lub ogólne stwierdzenie",
            "note": "Nienawidzi, gdy jej przeszkadzano. - Nienawidzi, gdy jej przeszkadzano."
        },
        {
            "en": "having been done",
            "ua": "Poprzednia (wcześniejsza) akcja",
            "note": "Otrzymawszy ostrzeżenie, zachował ostrożność. — Po otrzymaniu ostrzeżenia był bardziej ostrożny."
        },
        {
            "en": "being done (прийменник)",
            "ua": "Proces/współbieżność",
            "note": "Niezauważony, wyszedł. - Zostawił niezauważony."
        },
        {
            "en": "having been done (причина)",
            "ua": "Związek przyczynowy",
            "note": "Ponieważ została odrzucona, próbowała ponownie. — Otrzymawszy odmowę, próbowała ponownie."
        }
    ],
    "warning": "📌 Czasownik doskonały podkreśla, że ​​czynność miała miejsce PRZED czynnością główną w zdaniu!"
}

{
    "title": "6. Porównanie: Gerund aktywny i pasywny",
    "intro": "Kiedy podmiot wykonuje akcję (aktywną) lub podlega działaniu (bierną):",
    "rows": [
        {
            "en": "Active: He likes helping others.",
            "ua": "Lubi pomagać innym.",
            "note": "On (podmiot) pomaga."
        },
        {
            "en": "Passive: He likes being helped.",
            "ua": "Lubi, gdy mu się pomaga.",
            "note": "On (podmiot) otrzymuje pomoc."
        },
        {
            "en": "Active: I remember telling her.",
            "ua": "Pamiętam, że jej mówiłem.",
            "note": "powiedziałem"
        },
        {
            "en": "Passive: I remember being told.",
            "ua": "Pamiętam, co mi powiedzieli.",
            "note": "Powiedziano mi."
        }
    ],
    "warning": "📌 Jeśli podmiot jest wykonawcą czynności — gerund czynny. Jeśli podmiot podlega działaniu - bierny gerund."
}

{
    "title": "7. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pominięcie bycia w stronie biernej gerund.",
            "wrong": "She hates criticized.",
            "right": "✅ She hates being criticized."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Używanie V1 zamiast V3.",
            "wrong": "He enjoys being praise.",
            "right": "✅ He enjoys being praised."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Pomieszanie prostego i doskonałego.",
            "wrong": "Being warned yesterday, he was careful.",
            "right": "✅ Having been warned yesterday, he was careful."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Nieprawidłowa kolejność słów w czasie idealnym.",
            "wrong": "been having done",
            "right": "✅ having been done"
        }
    ]
}
